steps.command:
cat > ${DEPLOYMENT_PATH}/.env << 'EOF'
DOCKER_IMAGE=${DOCKER_IMAGE}
APP_NAME=${APP_NAME}
APP_PORT=${APP_PORT}
NODE_ENV=${NODE_ENV}
MONGODB_ROOT_PASSWORD=${MONGODB_ROOT_PASSWORD}
MONGODB_USER=${MONGODB_USER}
MONGODB_PASSWORD=${MONGODB_PASSWORD}
JWT_SECRET=${JWT_SECRET}
EOF

mkdir -p ${DEPLOYMENT_PATH}/mongo-init && cat > ${DEPLOYMENT_PATH}/mongo-init/init.js << 'EOF'
db.createUser({
  user: "${MONGODB_USER}",
  pwd: "${MONGODB_PASSWORD}",
  roles: ["readWrite"],
  db: "doez"
});
EOF
